css:
/* System 7 Desktop Pattern */
body {
  background: url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSI4IiBoZWlnaHQ9IjgiPjxyZWN0IHdpZHRoPSI4IiBoZWlnaHQ9IjgiIGZpbGw9IiNjY2MiLz48cmVjdCB4PSIwIiB5PSIwIiB3aWR0aD0iMSIgaGVpZ2h0PSIxIiBmaWxsPSIjYmJiIi8+PHJlY3QgeD0iNCIgeT0iNCIgd2lkdGg9IjEiIGhlaWdodD0iMSIgZmlsbD0iI2JiYiIvPjwvc3ZnPg==') repeat !important;
}

/* Window styling (Cards & Modals) with slightly rounded corners */
.bg-theme-surface, .card, .modal-content {
  background: #fff !important;
  border: 1px solid #000 !important;
  box-shadow: 1px 1px 0px #000, 2px 2px 0px rgba(0,0,0,0.5) !important;
  border-radius: 2px !important;
}

/* Solid Alerts & Badges (Fix for transparent background issue) */
.bg-theme-danger\/10, .bg-theme-warning\/10, .bg-theme-info\/10, .bg-theme-success\/10 {
  background-color: #fff !important;
  border: 2px solid currentColor !important;
  color: currentColor !important;
}
.text-theme-warning { color: #cc6600 !important; }
.border-theme-warning\/20, .border-theme-danger\/20, .border-theme-info\/20, .border-theme-success\/20 {
  border-color: currentColor !important;
}

/* System 7 Window Title Bars with Stripes */
.bg-theme-surface > .border-b, .border-b > h3.font-bold {
  position: relative;
  background: #e6e6e6;
  border-bottom: 1px solid #000;
  padding-top: 6px;
  padding-bottom: 6px;
  display: flex;
  justify-content: center;
  text-align: center;
}
.bg-theme-surface > .border-b::before, .border-b > h3.font-bold::before {
  content: ''; position: absolute; inset: 0 4px;
  background: repeating-linear-gradient(to bottom, transparent, transparent 1px, #666 1px, #666 2px);
  opacity: 0.5; z-index: 0;
  margin-top: 4px; margin-bottom: 4px;
}
/* Clear stripes behind the title text */
.bg-theme-surface > .border-b > *, .border-b > h3.font-bold > * {
  background: #e6e6e6;
  padding: 0 10px;
  position: relative;
  z-index: 1;
  font-weight: 700;
}

/* System 7 Buttons (Beveled 3D effect) */
.btn-primary, .btn-secondary {
  background: #fff !important;
  color: #000 !important;
  border: 1px solid #000 !important;
  border-radius: 8px !important;
  box-shadow: inset -1px -1px 0px #888, inset 1px 1px 0px #fff !important;
  position: relative;
  font-weight: 700;
}
.btn-primary::after, .btn-secondary::after {
  content: ''; position: absolute; inset: 1px;
  border: 1px solid #000; border-radius: 6px; pointer-events: none;
}
.btn-primary:active, .btn-secondary:active, .btn-primary:hover, .btn-secondary:hover {
  background: #ccc !important;
  box-shadow: inset 1px 1px 0px #888, inset -1px -1px 0px #fff !important;
}

/* Kill Anti-aliasing for true pixel look */
* {
  -webkit-font-smoothing: none !important;
  font-smooth: never !important;
}
::selection { background: #0000cc !important; color: #fff !important; }

/* Hover Inverts Table Rows (Mac style selection) */
tr:hover td { background: #0000cc !important; color: #fff !important; border-top: 1px solid #0000cc; border-bottom: 1px solid #0000cc; }
tr:hover td a, tr:hover td span, tr:hover td svg { color: #fff !important; }

/* System 7 Scrollbar */
::-webkit-scrollbar-track {
  background: url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSI0IiBoZWlnaHQ9IjQiPjxyZWN0IHdpZHRoPSIyIiBoZWlnaHQ9IjIiIGZpbGw9IiNjY2MiLz48cmVjdCB4PSIyIiB5PSIyIiB3aWR0aD0iMiIgaGVpZ2h0PSIyIiBmaWxsPSIjY2NjIi8+PC9zdmc+') #e6e6e6 !important;
  border-left: 1px solid #000;
}
::-webkit-scrollbar-thumb {
  background: #fff !important;
  border: 1px solid #000;
  box-shadow: inset -1px -1px 0px #888, inset 1px 1px 0px #fff;
}
